import React from 'react';

interface HeaderProps {
  balance: number;
}

const Header: React.FC<HeaderProps> = ({ balance }) => {
  const formatBalance = (val: number) =>
    val.toLocaleString('en-US');

  return (
    <header className="game-header">
      {/* Logo */}
      <div className="header-logo">
        <div className="logo-badge">
          <span className="logo-top">COCK</span>
          <span className="logo-bottom">4CAST</span>
        </div>
      </div>

      {/* Center hanging sign */}
      <div className="header-center">
        <div className="hanging-sign">
          <div className="sign-rope sign-rope-left" />
          <div className="sign-rope sign-rope-right" />
          <div className="sign-board">
            <span className="sign-label">Balance:</span>
            <span className="sign-value">{formatBalance(balance)} $</span>
          </div>
        </div>
      </div>

      {/* Right buttons */}
      <div className="header-right">
        <button className="header-btn" aria-label="How to play">
          <span className="header-btn-icon">❓</span>
          <span>How to play</span>
        </button>
        <button className="header-btn" aria-label="Settings">
          <span className="header-btn-icon">⚙️</span>
          <span>Settings</span>
        </button>
      </div>
    </header>
  );
};

export default Header;
